        <Button variant="danger" onClick={onConfirm} data-testid="delete-confirm-btn">Delete</Button>
      </DialogFooter>
    </Dialog>
  );
}

class AiErrorBoundary extends Component<{ children: ReactNode }, { hasError: boolean }> {
  state = { hasError: false };
  static getDerivedStateFromError() { return { hasError: true }; }
  componentDidCatch(_: Error, __: ErrorInfo) { /* silently suppress */ }
  render() { return this.state.hasError ? null : this.props.children; }
}

// ── MyWeek Page ─────────────────────────────────────────────────────────────

export default function MyWeek() {
  const [weekOffset, setWeekOffset] = useState(0);
  const weekStartDate = getWeekStartDate(weekOffset);

  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;

  const planApi = usePlanApi();
  const { data: planData, loading: planLoading, error: planError, refetch: refetchPlan } = useCurrentPlan(weekStartDate);
  const { data: rcdoTree } = useRcdoTree();

  const [showHistory, setShowHistory] = useState(false);
  const { data: planHistory, loading: historyLoading } = usePlanHistory(showHistory ? currentUserId : null);
  const [lineageCommitId, setLineageCommitId] = useState<string | null>(null);
  const { data: lineage, loading: lineageLoading } = useCarryForwardLineage(lineageCommitId);

  const ticketApi = useTicketApi();
  const [ticketFormVisible, setTicketFormVisible] = useState(false);
  const [ticketFormInitialValues, setTicketFormInitialValues] = useState<Partial<CreateTicketPayload>>({});

  type FormMode = "create" | "edit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [editingCommit, setEditingCommit] = useState<CommitResponse | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<CommitResponse | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [lockLoading, setLockLoading] = useState(false);
  const [showPreLockValidation, setShowPreLockValidation] = useState(false);
  const [lockValidationErrors, setLockValidationErrors] = useState<LockValidationError[]>([]);
  const [showLockConfirm, setShowLockConfirm] = useState(false);

  type ScopeChangeMode = "add" | "edit" | "remove" | null;
  const [scopeChangeMode, setScopeChangeMode] = useState<ScopeChangeMode>(null);
  const [scopeChangeTargetCommit, setScopeChangeTargetCommit] = useState<CommitResponse | null>(null);
  const [pendingEditPayload, setPendingEditPayload] = useState<UpdateCommitPayload | null>(null);
  const [pendingCreatePayload, setPendingCreatePayload] = useState<CreateCommitPayload | null>(null);
  const [scopeChangeSaving, setScopeChangeSaving] = useState(false);
  const [scopeChangeEvents, setScopeChangeEvents] = useState<ScopeChangeEventResponse[]>([]);
  const [showTimeline, setShowTimeline] = useState(false);

  const aiAssistanceEnabled = bridge.context.featureFlags.aiAssistanceEnabled;
  const { data: aiStatus } = useAiStatus();
  /** True when the feature flag is on AND the provider is reachable. */
  const aiComposerEnabled = aiAssistanceEnabled && (aiStatus?.available ?? false);

  const [showAiComposer, setShowAiComposer] = useState(false);
  /** Monotonically increasing counter — bumped after every commit CRUD to trigger lint re-run. */
  const [lintRefreshKey, setLintRefreshKey] = useState(0);
  /** Pre-filled values passed from AI composer → CommitForm when user switches to manual. */
  const [commitFormInitialValues, setCommitFormInitialValues] = useState<
    Partial<CreateCommitPayload>
  >({});

  const plan = planData?.plan;
  const commits = useMemo(() => planData?.commits ?? [], [planData]);
  const effectivePreLockErrors = useMemo(() => getEffectivePreLockErrors(commits, lockValidationErrors), [commits, lockValidationErrors]);
  const isDraft = plan?.state === "DRAFT";
  const isLocked = plan?.state === "LOCKED";

  // ── Handlers ──────────────────────────────────────────────────────────────

  /** Open AI composer (when AI is available) or CommitForm directly. */
  const handleOpenCreate = useCallback(() => {
    if (isLocked) {
      if (aiComposerEnabled) {
        // Post-lock: open AI composer first; the payload will flow through
        // handleCreateCommit which triggers the scope-change dialog.
        setShowAiComposer(true);
        setCommitFormInitialValues({});
      } else {
        setScopeChangeMode("add");
        setScopeChangeTargetCommit(null);
        setPendingCreatePayload(null);
      }
    } else if (aiComposerEnabled) {
      setShowAiComposer(true);
      setCommitFormInitialValues({});
    } else {
      setFormMode("create");
      setEditingCommit(null);
    }
    setActionError(null);
  }, [isLocked, aiComposerEnabled]);

  /** Always open the manual CommitForm, bypassing the AI composer. */
  const handleOpenManualCreate = useCallback(() => {
    setCommitFormInitialValues({});
    setFormMode("create");
    setEditingCommit(null);
    setActionError(null);
  }, []);

  const handleOpenEdit = useCallback((commit: CommitResponse) => {
    setFormMode("edit"); setEditingCommit(commit); setActionError(null);
  }, []);

  const handleFormCancel = useCallback(() => {
    setFormMode(null);
    setEditingCommit(null);
    setCommitFormInitialValues({});
  }, []);

  const handleCreateCommit = useCallback(async (payload: CreateCommitPayload) => {
    if (!plan) return;
    if (isLocked) { setPendingCreatePayload(payload); setScopeChangeMode("add"); setScopeChangeTargetCommit(null); setFormMode(null); return; }
    await planApi.createCommit(plan.id, payload);
    refetchPlan(); setFormMode(null); setLintRefreshKey((k) => k + 1);
  }, [plan, isLocked, planApi, refetchPlan]);

  const handleUpdateCommit = useCallback(async (payload: UpdateCommitPayload) => {
    if (!plan || !editingCommit) return;
    if (isLocked) { setPendingEditPayload(payload); setScopeChangeMode("edit"); setScopeChangeTargetCommit(editingCommit); setFormMode(null); setEditingCommit(null); return; }
    await planApi.updateCommit(plan.id, editingCommit.id, payload);
    refetchPlan(); setFormMode(null); setEditingCommit(null); setLintRefreshKey((k) => k + 1);
  }, [plan, editingCommit, isLocked, planApi, refetchPlan]);

  const handleDeleteRequest = useCallback((commitId: string) => {
    const commit = commits.find((c) => c.id === commitId);
    if (!commit) return;
    if (isLocked) { setScopeChangeMode("remove"); setScopeChangeTargetCommit(commit); }
    else { setDeleteTarget(commit); }
  }, [commits, isLocked]);

  const handleDeleteConfirm = useCallback(async () => {
    if (!plan || !deleteTarget) return;
    try { await planApi.deleteCommit(plan.id, deleteTarget.id); refetchPlan(); setLintRefreshKey((k) => k + 1); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Delete failed"); }
    finally { setDeleteTarget(null); }
  }, [plan, deleteTarget, planApi, refetchPlan]);

  const handleReorder = useCallback(async (orderedIds: string[]) => {
    if (!plan) return;
    try { await planApi.reorderCommits(plan.id, orderedIds); refetchPlan(); setLintRefreshKey((k) => k + 1); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Reorder failed"); }
  }, [plan, planApi, refetchPlan]);

  const handleCreateTicketFromCommit = useCallback((commit: CommitResponse) => {
    const teamId = bridge.context.currentTeam?.id;
    setTicketFormInitialValues({
      title: commit.title,
      ...(commit.description ? { description: commit.description } : {}),
      ...(commit.rcdoNodeId ? { rcdoNodeId: commit.rcdoNodeId } : {}),
      ...(commit.estimatePoints != null ? { estimatePoints: commit.estimatePoints } : {}),
      reporterUserId: currentUserId,
      ...(teamId ? { teamId } : {}),
    });
    setTicketFormVisible(true);
  }, [currentUserId, bridge]);

  const handleTicketFormSubmit = useCallback(async (payload: CreateTicketPayload) => {
    await ticketApi.createTicket(payload);
    setTicketFormVisible(false); setTicketFormInitialValues({});
  }, [ticketApi]);

  const handleLockButtonClick = useCallback(() => {
    setShowPreLockValidation(true); setLockValidationErrors([]); setShowLockConfirm(false);
  }, []);

  const handlePreLockContinue = useCallback(() => { setShowLockConfirm(true); }, []);

  const handleLock = useCallback(async () => {
    if (!plan) return;
    setLockLoading(true); setActionError(null);
    try {
      const response = await planApi.lockPlan(plan.id);
      if (!response.success) { setLockValidationErrors(response.errors ?? []); setShowLockConfirm(false); return; }
      setShowPreLockValidation(false); setShowLockConfirm(false); setLockValidationErrors([]); refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Lock failed"); setShowLockConfirm(false);
    } finally { setLockLoading(false); }
  }, [plan, planApi, refetchPlan]);

  const handleScopeChangeConfirm = useCallback(async (reason: string) => {
    if (!plan) return;
    setScopeChangeSaving(true); setActionError(null);
    try {
      if (scopeChangeMode === "add" && pendingCreatePayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "ADD", reason, commitData: pendingCreatePayload });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "remove" && scopeChangeTargetCommit) {
        const result = await planApi.applyScopeChange(plan.id, { action: "REMOVE", reason, commitId: scopeChangeTargetCommit.id });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "EDIT", reason, commitId: scopeChangeTargetCommit.id, changes: pendingEditPayload });
        setScopeChangeEvents(result.events);
      }
      refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Scope change failed");
    } finally {
      setScopeChangeSaving(false); setScopeChangeMode(null); setScopeChangeTargetCommit(null);
      setPendingEditPayload(null); setPendingCreatePayload(null);
    }
  }, [plan, scopeChangeMode, pendingCreatePayload, pendingEditPayload, scopeChangeTargetCommit, planApi, refetchPlan]);

  const handleScopeChangeCancel = useCallback(() => {
    setScopeChangeMode(null); setScopeChangeTargetCommit(null); setPendingEditPayload(null); setPendingCreatePayload(null);
  }, []);

  const handleLoadTimeline = useCallback(async () => {
    if (!plan) return;
    try { const result = await planApi.getScopeChangeTimeline(plan.id); setScopeChangeEvents(result.events); setShowTimeline(true); }
    catch { /* non-critical */ }
  }, [plan, planApi]);

  function buildRcdoLabels(): Record<string, string> {
    const map: Record<string, string> = {};
    function traverse(nodes: typeof rcdoTree, path: string[] = []) {
      if (!nodes) return;
      for (const n of nodes) { const nextPath = [...path, n.title]; map[n.id] = nextPath.join(" > "); traverse(n.children, nextPath); }
    }
    traverse(rcdoTree ?? []);
    return map;
  }
  const rcdoLabels = buildRcdoLabels();

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="flex flex-col gap-4" data-testid="page-my-week">
      {/* Page header */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">My Week</h2>
        {isDraft && (
          <div className="flex items-center gap-2">
            <Button
              variant="primary"
              onClick={handleOpenCreate}
              data-testid="add-commit-btn"
            >
              {aiComposerEnabled ? (
                <>
                  <Sparkles className="h-3.5 w-3.5 mr-1" aria-hidden="true" />
                  Add Commit
                </>
              ) : (
                "+ Add Commit"
              )}
            </Button>
            {aiComposerEnabled && (
              <button
                type="button"
                onClick={handleOpenManualCreate}
                className="text-xs text-muted hover:text-foreground underline cursor-pointer bg-transparent border-none p-0"
                data-testid="add-commit-manually-btn"
              >
                + Add manually
              </button>
            )}
          </div>
        )}
      </div>

      {/* Week selector */}
      <div data-testid="week-selector" className="flex items-center gap-2 flex-wrap">
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o - 1)} aria-label="Previous week" data-testid="prev-week-btn">
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <span data-testid="week-label" className="font-semibold text-sm min-w-[14rem] text-center">{formatWeekLabel(weekStartDate)}</span>
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o + 1)} aria-label="Next week" data-testid="next-week-btn">
          <ChevronRight className="h-4 w-4" />
        </Button>
        {weekOffset !== 0 && (
          <Button variant="secondary" size="sm" onClick={() => setWeekOffset(0)} data-testid="current-week-btn">Today</Button>
        )}
      </div>

      {/* Loading */}
      {planLoading && (
        <div role="status" aria-label="Loading plan" data-testid="plan-loading" className="text-sm text-muted">Loading plan…</div>
      )}

      {/* Error */}
      {planError && (
        <div role="alert" data-testid="plan-error" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2.5 text-sm text-foreground font-semibold">
          Failed to load plan: {planError.message}
        </div>
      )}

      {/* Plan header */}
      {plan && (
        <Card data-testid="plan-header">
          <CardHeader>
            <div className="flex items-center gap-2.5">
              <PlanStateBadge state={plan.state} />
              <ComplianceBadge compliant={plan.compliant} />
            </div>
            <div className="flex items-center gap-2">
              {actionError && (
                <span role="alert" data-testid="plan-action-error" className="text-xs text-foreground font-semibold">{actionError}</span>
              )}
              {isDraft && (
                <Button variant="primary" size="sm" onClick={handleLockButtonClick} disabled={lockLoading} data-testid="lock-plan-btn">
                  <Lock className="h-3.5 w-3.5" />
                  {lockLoading ? "Locking…" : "Lock Plan"}
                </Button>
              )}
              {isLocked && (
                <Button variant="primary" size="sm" onClick={handleOpenCreate} data-testid="post-lock-add-commit-btn">
                  {aiComposerEnabled && <Sparkles className="h-3.5 w-3.5 mr-1" aria-hidden="true" />}
                  + Add Commit
                </Button>
              )}
              {(plan.state === "LOCKED" || plan.state === "RECONCILING") && (
                <Link to={`/weekly/reconcile/${plan.id}`} data-testid="reconcile-hint">
                  <Button variant="primary" size="sm" type="button">
                    <ArrowRight className="h-3.5 w-3.5 mr-1" />
                    {plan.state === "RECONCILING" ? "Continue Reconciliation" : "Reconcile This Week"}
                  </Button>
                </Link>
              )}
            </div>
          </CardHeader>
        </Card>
      )}

      {/* Proactive risk banners — shown only while LOCKED so critical signals are immediately visible */}
      {aiAssistanceEnabled && isLocked && plan && (
        <AiErrorBoundary>
          <ProactiveRiskBanner planId={plan.id} />
        </AiErrorBoundary>
      )}

      {/* Personal AI insights */}
      {aiAssistanceEnabled && plan && (
        <InsightPanel mode="personal" planId={plan.id} />
      )}

      {/* Auto-lock system banner */}
      {plan?.systemLockedWithErrors && (
        <div data-testid="auto-lock-banner" role="alert" className="flex items-start gap-2 rounded-default border border-neutral-300 bg-neutral-100 px-4 py-3 text-sm text-foreground">
          <AlertTriangle className="h-4 w-4 mt-0.5 shrink-0 text-neutral-500" aria-hidden="true" />
          <span><strong>System-locked with errors</strong> — this plan was automatically locked at the deadline. Some validation issues were present at lock time. Please review and reconcile.</span>
        </div>
      )}

      {/* Pre-lock validation panel */}
      {isDraft && showPreLockValidation && (
        <Card data-testid="pre-lock-validation-section">
          <CardHeader>
            <CardTitle>Pre-lock Validation</CardTitle>
            <Button variant="secondary" size="sm" type="button" onClick={() => setShowPreLockValidation(false)}>
              <X className="h-3.5 w-3.5" />Cancel
            </Button>
          </CardHeader>
          <CardContent>
            <PreLockValidationPanel errors={lockValidationErrors} commits={commits} />
            {effectivePreLockErrors.length === 0 && (
              <div className="mt-3.5 flex justify-end">
                <Button variant="primary" onClick={handlePreLockContinue} data-testid="pre-lock-continue-btn">
                  Continue to Lock →
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Capacity meter */}
      {plan && <CapacityMeter commits={commits} budgetPoints={plan.capacityBudgetPoints} isManagerOverride={plan.capacityBudgetPoints !== 10} />}

      {/* Soft warnings */}
      {commits.length > 0 && <SoftWarningsPanel commits={commits} />}

      {/* Inline AI commit quality hints — auto-runs in DRAFT so feedback appears without any extra click */}
      {aiAssistanceEnabled && isDraft && plan && commits.length > 0 && (
        <div data-testid="inline-ai-lint-panel">
          <AiErrorBoundary>
            <AiLintPanel planId={plan.id} userId={currentUserId} autoRun refreshKey={lintRefreshKey} />
          </AiErrorBoundary>
        </div>
      )}

      {/* Commit list */}
      {plan && (
        <CommitList
          commits={commits}
          planState={plan.state}
          onReorder={handleReorder}
          onEdit={handleOpenEdit}
          onDelete={handleDeleteRequest}
          rcdoLabels={rcdoLabels}
          onViewLineage={(commitId) => setLineageCommitId(commitId)}
          onCreateTicket={handleCreateTicketFromCommit}
        />
      )}

      {/* Scope change timeline */}
      {isLocked && scopeChangeEvents.length > 0 && (
        <section aria-labelledby="scope-timeline-heading">
          <h3 id="scope-timeline-heading" className="m-0 mb-2.5 text-sm font-bold">Post-lock Changes</h3>
          <ScopeChangeTimeline events={scopeChangeEvents} />
        </section>
      )}
      {isLocked && !showTimeline && (
        <Button variant="secondary" size="sm" type="button" onClick={() => void handleLoadTimeline()} data-testid="load-scope-timeline-btn" className="self-start">
          View scope-change history
        </Button>
      )}

      {/* AI Commit Composer — works for both DRAFT (direct create) and LOCKED (flows through scope-change) */}
      {showAiComposer && plan && (isDraft || isLocked) && (
        <AiErrorBoundary>
          <AiCommitComposer
            planId={plan.id}
            existingCommits={commits}
            onSubmit={async (payload) => {
              await handleCreateCommit(payload);
              setShowAiComposer(false);
            }}
            onSwitchToManual={(preFilled) => {
              setShowAiComposer(false);
              setCommitFormInitialValues(preFilled);
              setFormMode("create");
              setEditingCommit(null);
            }}
            onCancel={() => setShowAiComposer(false)}
          />
        </AiErrorBoundary>
      )}

      {/* CommitForm modals */}
      {formMode === "create" && plan && !isLocked && (
        <CommitForm
          mode="create"
          planId={plan.id}
          rcdoTree={rcdoTree ?? []}
          existingCommits={commits}
          onSubmit={handleCreateCommit}
          onCancel={handleFormCancel}
          initialValues={commitFormInitialValues}
        />
      )}
      {formMode === "edit" && plan && editingCommit && (
        <CommitForm mode="edit" commit={editingCommit} rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={handleUpdateCommit} onCancel={handleFormCancel} />
      )}
      {scopeChangeMode === "add" && !pendingCreatePayload && plan && (
        <CommitForm mode="create" planId={plan.id} rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={async (payload) => { setPendingCreatePayload(payload); }} onCancel={handleScopeChangeCancel} />
      )}

      {/* Delete confirm */}
      {deleteTarget && !isLocked && (
        <DeleteConfirmDialog title={deleteTarget.title} onConfirm={handleDeleteConfirm} onCancel={() => setDeleteTarget(null)} />
      )}

      {/* Ticket form */}
      {ticketFormVisible && (
        <TicketForm mode="create" initialValues={ticketFormInitialValues} currentUserId={currentUserId} {...(bridge.context.currentTeam ? { currentTeamId: bridge.context.currentTeam.id } : {})} rcdoTree={rcdoTree ?? []} onSubmit={handleTicketFormSubmit} onCancel={() => { setTicketFormVisible(false); setTicketFormInitialValues({}); }} />
      )}

      {/* Lock confirm */}
      {showLockConfirm && plan && (
        <LockConfirmDialog commits={commits} capacityBudgetPoints={plan.capacityBudgetPoints} weekLabel={formatWeekLabel(weekStartDate)} onConfirm={() => void handleLock()} onCancel={() => setShowLockConfirm(false)} isLocking={lockLoading} />
      )}

      {/* Scope change dialogs */}
      {scopeChangeMode === "add" && pendingCreatePayload && (
        <ScopeChangeDialog action="ADD" commit={null} newCommitTitle={pendingCreatePayload.title} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload && (
        <ScopeChangeDialog action="EDIT" commit={scopeChangeTargetCommit} proposedChanges={pendingEditPayload as Partial<CommitResponse>} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "remove" && scopeChangeTargetCommit && (
        <ScopeChangeDialog action="REMOVE" commit={scopeChangeTargetCommit} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}

      {/* Plan History */}
      <Card>
        <CardHeader>
          <CardTitle>Plan History</CardTitle>
          <Button variant="secondary" size="sm" type="button" onClick={() => setShowHistory((s) => !s)} data-testid="toggle-plan-history-btn">
            {showHistory ? "Hide" : "Show history"}
          </Button>
        </CardHeader>
        {showHistory && (
          <CardContent>
            <PlanHistoryView entries={planHistory ?? []} loading={historyLoading} />
          </CardContent>
        )}
      </Card>

      {/* Carry-forward lineage */}
      {lineageCommitId && (
        <Card data-testid="cf-lineage-section">
          <CardHeader>
            <CardTitle>Carry-forward Lineage</CardTitle>
            <Button variant="ghost" size="icon" type="button" onClick={() => setLineageCommitId(null)} aria-label="Close lineage" className="h-7 w-7">
              <X className="h-4 w-4" />
            </Button>
          </CardHeader>
          <CardContent>
            {lineage && <CarryForwardLineageView lineage={lineage} loading={lineageLoading} />}
            {lineageLoading && !lineage && (
              <div data-testid="cf-lineage-loading" role="status" className="text-sm text-muted">Loading lineage…</div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

/**
 * CommitDraftAssistButton — "✨ AI Suggest" button that calls the existing
 * CommitDraftAssistService backend and renders inline suggestions.
 *
 * SOTA note: Completes the wiring of an existing backend capability to the
 * frontend (ai-eval-roadmap Phase 3a). Every suggestion shows rationale and
 * is accept/dismiss-able per PRD §17 ("assistive, not authoritarian").
 */
import { useState, useCallback } from "react";
import { Sparkles, Check, Loader2 } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import type { CommitDraftAssistResponse } from "../../api/aiApi.js";

interface CommitDraftAssistButtonProps {
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
  onAcceptTitle?: ((title: string) => void) | undefined;
  onAcceptDescription?: ((description: string) => void) | undefined;
  onAcceptSuccessCriteria?: ((criteria: string) => void) | undefined;
  onAcceptEstimatePoints?: ((points: number) => void) | undefined;
  onAcceptChessPiece?: ((piece: string) => void) | undefined;
  className?: string | undefined;
}

interface SuggestionField {
  label: string;
  current: string;
  suggested: string;
  onAccept: () => void;
}

export function CommitDraftAssistButton({
  planId,
  commitId,
  currentTitle,
  currentDescription,
  currentSuccessCriteria,
  currentEstimatePoints,
  chessPiece,
  onAcceptTitle,
  onAcceptDescription,
  onAcceptSuccessCriteria,
  onAcceptEstimatePoints,
  onAcceptChessPiece,
  className,
}: CommitDraftAssistButtonProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CommitDraftAssistResponse | null>(null);
  const [accepted, setAccepted] = useState<Set<string>>(new Set());
  const [error, setError] = useState<string | null>(null);

  const isAvailable = aiStatus?.available ?? false;

  const handleRequest = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    setAccepted(new Set());
    try {
      const response = await aiApi.commitDraftAssist({
        userId,
        planId,
        commitId,
        currentTitle,
        currentDescription,
        currentSuccessCriteria,
        currentEstimatePoints,
        chessPiece,
      });
      if (!response.aiAvailable) {
        setError("AI is currently unavailable. Try again later.");
        return;
      }
      setResult(response);
    } catch {
      setError("Failed to get AI suggestions.");
    } finally {
      setLoading(false);
    }
  }, [
    aiApi, userId, planId, commitId, currentTitle,
    currentDescription, currentSuccessCriteria, currentEstimatePoints, chessPiece,
  ]);

  const handleAccept = useCallback((field: string, acceptFn: () => void) => {
    acceptFn();
    setAccepted((prev) => new Set(prev).add(field));
  }, []);

  // Build suggestion fields from the response
  const suggestions: SuggestionField[] = [];
  if (result) {
    if (result.suggestedTitle && onAcceptTitle) {
      suggestions.push({
        label: "Title",
        current: currentTitle,
        suggested: result.suggestedTitle,
        onAccept: () => onAcceptTitle(result.suggestedTitle!),
      });
    }
    if (result.suggestedDescription && onAcceptDescription) {
      suggestions.push({
        label: "Description",
        current: currentDescription ?? "",
        suggested: result.suggestedDescription,
        onAccept: () => onAcceptDescription(result.suggestedDescription!),
      });
    }
    if (result.suggestedSuccessCriteria && onAcceptSuccessCriteria) {
      suggestions.push({
        label: "Success Criteria",
        current: currentSuccessCriteria ?? "",
        suggested: result.suggestedSuccessCriteria,
        onAccept: () => onAcceptSuccessCriteria(result.suggestedSuccessCriteria!),
      });
    }
    if (result.suggestedEstimatePoints != null && onAcceptEstimatePoints) {
      suggestions.push({
        label: "Estimate",
        current: currentEstimatePoints != null ? `${currentEstimatePoints} pts` : "not set",
        suggested: `${result.suggestedEstimatePoints} pts`,
        onAccept: () => onAcceptEstimatePoints(result.suggestedEstimatePoints!),
      });
    }
    if (result.suggestedChessPiece && onAcceptChessPiece) {
      suggestions.push({
        label: "Chess Piece",
        current: chessPiece ?? "not set",
        suggested: result.suggestedChessPiece,
        onAccept: () => onAcceptChessPiece(result.suggestedChessPiece!),
      });
    }
  }

  const allGood = result && suggestions.length === 0;

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      {/* Trigger button */}
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={() => void handleRequest()}
        disabled={loading || !isAvailable || !currentTitle.trim()}
        data-testid="ai-draft-assist-btn"
        className="self-start text-primary hover:text-primary/80"
        title={!isAvailable ? "AI unavailable" : "Get AI suggestions for this commit"}
      >
        {loading ? (
          <Loader2 className="h-3.5 w-3.5 animate-spin mr-1" />
        ) : (
          <Sparkles className="h-3.5 w-3.5 mr-1" />
        )}
        {loading ? "Thinking…" : "AI Suggest"}
      </Button>

      {/* Error */}
      {error && (
        <p className="text-xs text-danger" data-testid="ai-draft-assist-error">{error}</p>
      )}

      {/* All good */}
      {allGood && (
        <div
          className="flex items-center gap-1.5 text-xs text-foreground bg-foreground/5 rounded-default px-2.5 py-1.5"
          data-testid="ai-draft-assist-good"
        >
          <Check className="h-3.5 w-3.5" />
          Looks good! No suggestions.
          {result.suggestionId && (
            <AiFeedbackButtons suggestionId={result.suggestionId} className="ml-auto" />
          )}
        </div>
      )}

      {/* Suggestions */}
      {suggestions.length > 0 && (
        <div
          className="rounded-default border border-primary/20 bg-primary/5 p-3 flex flex-col gap-2.5"
          data-testid="ai-draft-assist-suggestions"
        >
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-primary flex items-center gap-1">
              <Sparkles className="h-3 w-3" /> AI Suggestions
            </span>
            {result?.suggestionId && (
              <AiFeedbackButtons suggestionId={result.suggestionId} />
            )}
          </div>

          {suggestions.map((s) => {
            const isAccepted = accepted.has(s.label);
            return (
              <div
                key={s.label}
                className={cn(
                  "rounded-sm border px-2.5 py-2 text-xs",
                  isAccepted
                    ? "border-foreground/20 bg-foreground/5"
                    : "border-neutral-200 bg-white",
                )}
                data-testid={`ai-suggestion-${s.label.toLowerCase().replace(/\s/g, "-")}`}
              >
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1">
                    <Badge variant="default" className="mb-1 text-[0.6rem]">
                      {s.label}
                    </Badge>
                    {s.current && (
                      <p className="m-0 text-muted line-through">{s.current}</p>
                    )}
                    <p className="m-0 font-medium text-foreground">{s.suggested}</p>
                  </div>
                  {!isAccepted && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => handleAccept(s.label, s.onAccept)}
                      className="h-6 w-6 text-foreground hover:bg-neutral-100 shrink-0"
                      aria-label={`Accept ${s.label} suggestion`}
                      data-testid={`ai-accept-${s.label.toLowerCase().replace(/\s/g, "-")}`}
                    >
                      <Check className="h-3.5 w-3.5" />
                    </Button>
                  )}
                  {isAccepted && (
                    <span className="text-[0.6rem] text-foreground font-semibold">✓ Applied</span>
                  )}
                </div>
              </div>
            );
          })}

          {result?.rationale && (
            <p className="m-0 text-[0.65rem] text-muted italic" data-testid="ai-draft-assist-rationale">
              {result.rationale}
            </p>
          )}
        </div>
      )}
    </div>
  );
}

/**
 * ReconcileAssistPanel — "AI Assist Reconciliation" button that pre-fills
 * likely outcomes, generates a draft summary, and suggests carry-forwards.
 *
 * Phase 3b: Wires existing ReconcileAssistService backend to the Reconcile page.
 */
import { useState, useCallback } from "react";
import { Bot, Check, Loader2, RotateCcw, ArrowRight } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/Card.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import type {
  ReconcileAssistResponse,
  CommitOutcomeSuggestion,
  CarryForwardRecommendation,
} from "../../api/aiApi.js";
import type { CommitOutcome } from "../../api/planTypes.js";

const OUTCOME_COLORS: Record<string, string> = {
  ACHIEVED: "bg-foreground/10 text-foreground font-bold",
  PARTIALLY_ACHIEVED: "bg-neutral-200 text-neutral-600",
  NOT_ACHIEVED: "bg-neutral-300 text-foreground underline",
  CANCELED: "bg-neutral-100 text-neutral-500",
};

const OUTCOME_LABELS: Record<string, string> = {
  ACHIEVED: "Achieved",
  PARTIALLY_ACHIEVED: "Partial",
  NOT_ACHIEVED: "Not Achieved",
  CANCELED: "Canceled",
};

interface ReconcileAssistPanelProps {
  planId: string;
  /** Callback when the user accepts an outcome suggestion. */
  onAcceptOutcome?: ((commitId: string, outcome: CommitOutcome) => void) | undefined;
  /** Callback when the user accepts a carry-forward recommendation. */
  onAcceptCarryForward?: ((commitId: string) => void) | undefined;
  className?: string | undefined;
}

export function ReconcileAssistPanel({
  planId,
  onAcceptOutcome,
  onAcceptCarryForward,
  className,
}: ReconcileAssistPanelProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ReconcileAssistResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [appliedOutcomes, setAppliedOutcomes] = useState<Set<string>>(new Set());
  const [appliedCarryForwards, setAppliedCarryForwards] = useState<Set<string>>(new Set());

  const isAvailable = aiStatus?.available ?? false;

  const handleRequest = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    setAppliedOutcomes(new Set());
    setAppliedCarryForwards(new Set());
    try {
      const response = await aiApi.reconcileAssist({ planId, userId });
      if (!response.aiAvailable) {
        setError("AI is currently unavailable.");
        return;
      }
      setResult(response);
    } catch {
      setError("Failed to get reconciliation suggestions.");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  const handleApplyOutcome = useCallback(
    (suggestion: CommitOutcomeSuggestion) => {
      onAcceptOutcome?.(suggestion.commitId, suggestion.suggestedOutcome as CommitOutcome);
      setAppliedOutcomes((prev) => new Set(prev).add(suggestion.commitId));
    },
    [onAcceptOutcome],
  );

  const handleApplyCarryForward = useCallback(
    (rec: CarryForwardRecommendation) => {
      onAcceptCarryForward?.(rec.commitId);
      setAppliedCarryForwards((prev) => new Set(prev).add(rec.commitId));
    },
    [onAcceptCarryForward],
  );

  // Not yet requested
  if (!result && !loading && !error) {
    return (
      <div className={cn("flex items-center gap-2", className)}>
        <Button
          variant="ghost"
          size="sm"
          onClick={() => void handleRequest()}
          disabled={!isAvailable}
          className="text-primary hover:text-primary/80 border border-dashed border-primary/30"
          data-testid="reconcile-assist-btn"
          title={!isAvailable ? "AI unavailable" : "Get AI suggestions for reconciliation"}
        >
          <Bot className="h-3.5 w-3.5 mr-1.5" />
          AI Assist Reconciliation
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div
        className={cn("flex items-center gap-2 text-sm text-muted animate-pulse", className)}
        data-testid="reconcile-assist-loading"
      >
        <Loader2 className="h-4 w-4 animate-spin" />
        Analyzing your week…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div
        className={cn(
          "flex items-center justify-between gap-2 rounded-default border border-danger/30 bg-danger/5 px-3 py-2",
          className,
        )}
        data-testid="reconcile-assist-error"
      >
        <span className="text-xs text-danger">{error}</span>
        <Button
          variant="ghost"
          size="sm"
          onClick={() => void handleRequest()}
          className="h-6 text-xs"
          data-testid="reconcile-assist-retry"
        >
          <RotateCcw className="h-3 w-3 mr-1" />
          Retry
        </Button>
      </div>
    );
  }

  if (!result) return null;

  const hasOutcomes = result.likelyOutcomes.length > 0;
  const hasCarryForwards = result.carryForwardRecommendations.length > 0;
  const hasSummary = result.draftSummary && result.draftSummary.trim().length > 0;

  return (
    <Card className={cn("w-full", className)} data-testid="reconcile-assist-panel">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Bot className="h-4 w-4 text-primary" />
          AI Reconciliation Suggestions
        </CardTitle>
        <div className="flex items-center gap-2">
          {result.suggestionId && (
            <AiFeedbackButtons suggestionId={result.suggestionId} />
          )}
          <Button
            variant="ghost"
            size="sm"
            onClick={() => void handleRequest()}
            className="h-6 text-xs"
            data-testid="reconcile-assist-refresh"
          >
            <RotateCcw className="h-3 w-3" />
          </Button>
        </div>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* Draft summary */}
        {hasSummary && (
          <div data-testid="reconcile-assist-summary">
            <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
              Week Summary
            </p>
            <p className="m-0 text-sm leading-relaxed text-foreground bg-background rounded-default px-3 py-2 border border-border">
              {result.draftSummary}
            </p>
          </div>
        )}

        {/* Outcome suggestions */}
        {hasOutcomes && (
          <div data-testid="reconcile-assist-outcomes">
            <p className="m-0 mb-2 text-xs font-semibold text-muted uppercase tracking-wider">
              Suggested Outcomes
            </p>
            <div className="flex flex-col gap-1.5">
              {result.likelyOutcomes.map((suggestion) => {
                const isApplied = appliedOutcomes.has(suggestion.commitId);
                const colorCls =
                  OUTCOME_COLORS[suggestion.suggestedOutcome] ?? "bg-neutral-100 text-neutral-700";
                return (
                  <div
                    key={suggestion.commitId}
                    className={cn(
                      "flex items-start gap-2 rounded-sm border px-2.5 py-2 text-xs",
                      isApplied ? "border-foreground/20 bg-foreground/5" : "border-border",
                    )}
                    data-testid={`outcome-suggestion-${suggestion.commitId}`}
                  >
                    <div className="flex-1 min-w-0">
                      <span className="font-semibold">{suggestion.commitTitle}</span>
                      <div className="flex items-center gap-1.5 mt-1">
                        <Badge
                          variant="default"
                          className={cn("text-[0.6rem]", colorCls)}
                        >
                          {OUTCOME_LABELS[suggestion.suggestedOutcome] ??
                            suggestion.suggestedOutcome}
                        </Badge>
                        <span className="text-muted">{suggestion.rationale}</span>
                      </div>
                    </div>
                    {!isApplied && onAcceptOutcome && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        onClick={() => handleApplyOutcome(suggestion)}
                        className="h-6 w-6 text-primary hover:bg-primary/10 shrink-0"
                        aria-label={`Apply ${suggestion.suggestedOutcome} to ${suggestion.commitTitle}`}
                        data-testid={`apply-outcome-${suggestion.commitId}`}
                      >
                        <Check className="h-3.5 w-3.5" />
                      </Button>
                    )}
                    {isApplied && (
                      <span className="text-[0.6rem] text-foreground font-semibold shrink-0">
                        ✓ Applied
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Carry-forward recommendations */}
        {hasCarryForwards && (
          <div data-testid="reconcile-assist-carry-forwards">
            <p className="m-0 mb-2 text-xs font-semibold text-muted uppercase tracking-wider">
              Carry Forward Recommendations
            </p>
            <div className="flex flex-col gap-1.5">
              {result.carryForwardRecommendations.map((rec) => {
                const isApplied = appliedCarryForwards.has(rec.commitId);
                return (
                  <div
                    key={rec.commitId}
                    className={cn(
                      "flex items-start gap-2 rounded-sm border px-2.5 py-2 text-xs",
                      isApplied
                        ? "border-foreground/15 bg-foreground/[0.03]"
                        : "border-border",
                    )}
                    data-testid={`carry-forward-rec-${rec.commitId}`}
                  >
                    <ArrowRight className="h-3.5 w-3.5 mt-0.5 text-muted shrink-0" />
                    <div className="flex-1 min-w-0">
                      <span className="font-semibold">{rec.commitTitle}</span>
                      <p className="m-0 mt-0.5 text-muted">{rec.rationale}</p>
                    </div>
                    {!isApplied && onAcceptCarryForward && (
                      <Button
                        type="button"
                        variant="ghost"
                        size="sm"
                        onClick={() => handleApplyCarryForward(rec)}
                        className="h-6 text-xs text-foreground hover:bg-neutral-100 shrink-0"
                        aria-label={`Carry forward ${rec.commitTitle}`}
                        data-testid={`apply-carry-forward-${rec.commitId}`}
                      >
                        🔁 Carry Forward
                      </Button>
                    )}
                    {isApplied && (
                      <span className="text-[0.6rem] text-foreground font-semibold shrink-0">
                        ✓ Queued
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {!hasOutcomes && !hasCarryForwards && !hasSummary && (
          <p className="text-xs text-muted italic" data-testid="reconcile-assist-empty">
            No additional suggestions — your reconciliation looks straightforward.
          </p>
        )}
      </CardContent>
    </Card>
  );
}

/**
 * TypeScript types for Plan and Commit API request/response payloads.
 * Mirror the backend DTO records from PlanController / CommitService.
 */

export type PlanState = "DRAFT" | "LOCKED" | "RECONCILING" | "RECONCILED";

export type ChessPiece =
  | "KING"
  | "QUEEN"
  | "ROOK"
  | "BISHOP"
  | "KNIGHT"
  | "PAWN";

export type CommitOutcome =
  | "ACHIEVED"
  | "PARTIALLY_ACHIEVED"
  | "NOT_ACHIEVED"
  | "CANCELED";

/** Valid Fibonacci-scale estimate point values (mirrors shared/constants.ts). */
export type EstimatePoints = 1 | 2 | 3 | 5 | 8;
export const VALID_ESTIMATE_POINTS: EstimatePoints[] = [1, 2, 3, 5, 8];

/** Plan header — mirrors PlanResponse Java record. */
export interface PlanResponse {
  readonly id: string;
  readonly ownerUserId: string;
  readonly teamId: string;
  /** ISO date: yyyy-MM-dd (Monday of the plan week). */
  readonly weekStartDate: string;
  readonly state: PlanState;
  /** ISO datetime — manual-lock deadline. */
  readonly lockDeadline: string;
  /** ISO datetime — reconciliation deadline. */
  readonly reconcileDeadline: string;
  readonly capacityBudgetPoints: number;
  readonly compliant: boolean;
  readonly systemLockedWithErrors: boolean;
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Single commit — mirrors CommitResponse Java record. */
export interface CommitResponse {
  readonly id: string;
  readonly planId: string;
  readonly ownerUserId: string;
  readonly title: string;
  readonly description?: string;
  readonly chessPiece: ChessPiece;
  readonly priorityOrder: number;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
  readonly outcome?: CommitOutcome;
  readonly outcomeNotes?: string;
  readonly carryForwardStreak: number;
  readonly createdAt: string;
  readonly updatedAt: string;
}

/** Combined response — mirrors PlanWithCommitsResponse Java record. */
export interface PlanWithCommitsResponse {
  readonly plan: PlanResponse;
  readonly commits: CommitResponse[];
  readonly totalPoints: number;
}

/** POST /api/plans request body — mirrors CreatePlanRequest Java record. */
export interface GetOrCreatePlanPayload {
  readonly userId: string;
  readonly weekStartDate?: string;
}

/** POST /api/plans/{planId}/commits request body — mirrors CreateCommitRequest. */
export interface CreateCommitPayload {
  readonly title: string;
  readonly chessPiece: ChessPiece;
  readonly description?: string;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
}

/**
 * PUT /api/plans/{planId}/commits/{commitId} request body.
 * Null/omitted fields are treated as "no-op" by the backend.
 */
export interface UpdateCommitPayload {
  readonly title?: string;
  readonly chessPiece?: ChessPiece;
  readonly description?: string;
  readonly rcdoNodeId?: string;
  readonly workItemId?: string;
  readonly estimatePoints?: EstimatePoints;
  readonly successCriteria?: string;
}

// ── Lock types ────────────────────────────────────────────────────────────────

/** A single hard-validation failure returned by POST /api/plans/{id}/lock. */
export interface LockValidationError {
  readonly field: string;
  readonly message: string;
}

/**
 * Response from POST /api/plans/{id}/lock.
 * success=false → errors contains the hard validation failures.
 */
export interface LockResponse {
  readonly success: boolean;
  readonly plan: PlanWithCommitsResponse | null;
  readonly errors: LockValidationError[];
}

// ── Scope-change types ────────────────────────────────────────────────────────

export type ScopeChangeCategory =
  | "COMMIT_ADDED"
  | "COMMIT_REMOVED"
  | "ESTIMATE_CHANGED"
  | "CHESS_PIECE_CHANGED"
  | "RCDO_CHANGED"
  | "PRIORITY_CHANGED";

export type ScopeChangeAction = "ADD" | "REMOVE" | "EDIT";

/** Single scope-change event — mirrors ScopeChangeEventResponse Java record. */
export interface ScopeChangeEventResponse {
  readonly id: string;
  readonly planId: string;
  readonly commitId: string | null;
  readonly category: ScopeChangeCategory;
  readonly changedByUserId: string | null;
  readonly reason: string;
  readonly previousValue: string | null;
  readonly newValue: string | null;
  readonly createdAt: string;
}

/** Timeline response — mirrors ScopeChangeTimelineResponse Java record. */
export interface ScopeChangeTimelineResponse {
  readonly events: ScopeChangeEventResponse[];
  readonly managerExceptions: unknown[];
}

/** Request body for POST /api/plans/{id}/scope-changes. */
export interface ScopeChangePayload {
  readonly action: ScopeChangeAction;
  readonly reason: string;
  readonly commitId?: string;
  readonly commitData?: CreateCommitPayload;
  readonly changes?: UpdateCommitPayload;
}

// ── Reconciliation types ──────────────────────────────────────────────────────

/** Per-commit reconciliation view — mirrors ReconcileCommitView Java record. */
export interface ReconcileCommitView {
  readonly commitId: string;
  readonly currentTitle: string;
  readonly currentChessPiece: ChessPiece;
  readonly currentEstimatePoints: number | null;
  readonly currentOutcome: CommitOutcome | null;
  readonly currentOutcomeNotes: string | null;
  /** Baseline snapshot values (null for post-lock-added commits). */
  readonly baselineSnapshot: Record<string, unknown> | null;
  readonly scopeChanges: ScopeChangeEventResponse[];
  readonly linkedTicketStatus: string | null;
  readonly addedPostLock: boolean;
  readonly removedPostLock: boolean;
}

/** Full reconciliation view response — mirrors ReconciliationViewResponse. */
export interface ReconciliationViewResponse {
  readonly plan: PlanResponse;
  readonly commits: ReconcileCommitView[];
  readonly baselineTotalPoints: number;
  readonly currentTotalPoints: number;
  readonly commitCount: number;
  readonly outcomesSetCount: number;
}

/** Request body for PUT /api/plans/{id}/commits/{commitId}/outcome. */
export interface SetOutcomePayload {
  readonly outcome: CommitOutcome;
  readonly notes?: string | undefined;
}

// ── Carry-forward types ───────────────────────────────────────────────────────

export type CarryForwardReason =
  | "BLOCKED_BY_DEPENDENCY"
  | "SCOPE_EXPANDED"
  | "REPRIORITIZED"
  | "RESOURCE_UNAVAILABLE"
  | "TECHNICAL_OBSTACLE"
  | "EXTERNAL_DELAY"
  | "UNDERESTIMATED"
  | "STILL_IN_PROGRESS";

/** Request body for POST /api/plans/{planId}/commits/{commitId}/carry-forward. */
export interface CarryForwardPayload {
  readonly targetWeekStart: string;
  readonly reason: CarryForwardReason;
  readonly reasonText?: string | undefined;
}

package com.weeklycommit.ai.eval;

import static org.assertj.core.api.Assertions.assertThat;

import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.ai.provider.OpenRouterAiProvider;
import java.io.File;
import java.io.InputStream;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Stream;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.TestInstance;
