package com.weeklycommit.domain.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;

/**
 * Derived read-model: one row per active carry-forward commit, tracking
 * provenance and streak length.
 */
@Entity
@Table(name = "carry_forward_fact")
public class CarryForwardFact {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	/** The current (target) commit in the chain. */
	@Column(name = "commit_id", nullable = false)
	private UUID commitId;

	/** The week in which the original (root) commit was created. */
	@Column(name = "source_week", nullable = false)
	private LocalDate sourceWeek;

	/** The week in which this commit currently lives. */
	@Column(name = "current_week", nullable = false)
	private LocalDate currentWeek;

	/** Number of consecutive weeks this work has been carried forward. */
	@Column(name = "streak_length", nullable = false)
	private int streakLength;

	@Column(name = "rcdo_node_id")
	private UUID rcdoNodeId;

	@Column(name = "chess_piece")
	private String chessPiece;

	@Column(name = "refreshed_at", nullable = false)
	private Instant refreshedAt = Instant.now();

	// ---- Getters / Setters -----------------------------------------------

	public UUID getId() {
		return id;
	}
	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getCommitId() {
		return commitId;
	}
	public void setCommitId(UUID commitId) {
		this.commitId = commitId;
	}

	public LocalDate getSourceWeek() {
		return sourceWeek;
	}
	public void setSourceWeek(LocalDate sourceWeek) {
		this.sourceWeek = sourceWeek;
	}

	public LocalDate getCurrentWeek() {
		return currentWeek;
	}
	public void setCurrentWeek(LocalDate currentWeek) {
		this.currentWeek = currentWeek;
	}

	public int getStreakLength() {
		return streakLength;
	}
	public void setStreakLength(int streakLength) {
		this.streakLength = streakLength;
	}

	public UUID getRcdoNodeId() {
		return rcdoNodeId;
	}
	public void setRcdoNodeId(UUID rcdoNodeId) {
		this.rcdoNodeId = rcdoNodeId;
	}

	public String getChessPiece() {
		return chessPiece;
	}
	public void setChessPiece(String chessPiece) {
		this.chessPiece = chessPiece;
	}

	public Instant getRefreshedAt() {
		return refreshedAt;
	}
	public void setRefreshedAt(Instant refreshedAt) {
		this.refreshedAt = refreshedAt;
	}
}

package com.weeklycommit.domain.repository;

import com.weeklycommit.domain.entity.CarryForwardFact;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

@Repository
public interface CarryForwardFactRepository extends JpaRepository<CarryForwardFact, UUID> {

	Optional<CarryForwardFact> findByCommitId(UUID commitId);

	List<CarryForwardFact> findByCurrentWeekBetween(LocalDate from, LocalDate to);
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Optional;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

/**
 * Manages registered {@link AiProvider} implementations and exposes the active
 * provider for the application.
 *
 * <p>
 * AI can be disabled globally via the {@code ai.enabled} property (default
 * {@code true}). When disabled, {@link #isAiEnabled()} returns {@code false}
 * and {@link #generateSuggestion(AiContext)} returns
 * {@link AiSuggestionResult#unavailable()} without calling any provider.
 *
 * <p>
 * Provider selection: the first registered provider that reports
 * {@link AiProvider#isAvailable()} is used. If none are available, the result
 * is also unavailable.
 */
@Component
public class AiProviderRegistry {

	private static final Logger log = LoggerFactory.getLogger(AiProviderRegistry.class);

	@Value("${ai.enabled:true}")
	private boolean aiEnabled;

	private final List<AiProvider> providers;

	public AiProviderRegistry(List<AiProvider> providers) {
		this.providers = providers != null ? providers : List.of();
	}

	/**
	 * Returns {@code true} when AI is enabled via feature flag AND at least one
	 * provider is registered.
	 */
	public boolean isAiEnabled() {
		return aiEnabled && !providers.isEmpty();
	}

	/**
	 * Returns the first registered provider that reports itself as available, or
	 * {@link Optional#empty()} if none are.
	 */
	public Optional<AiProvider> getActiveProvider() {
		if (!aiEnabled) {
			log.debug("AI is disabled via feature flag");
			return Optional.empty();
		}
		return providers.stream().filter(AiProvider::isAvailable).findFirst();
	}

	/**
	 * Convenience method: generates a suggestion using the active provider, or
	 * returns {@link AiSuggestionResult#unavailable()} with graceful degradation if
	 * the provider is unavailable or AI is disabled.
	 *
	 * <p>
	 * Core workflow is never affected — callers should check
	 * {@link AiSuggestionResult#available()} on the response.
	 *
	 * @param context
	 *            the input context
	 * @return suggestion result, never {@code null}
	 */
	public AiSuggestionResult generateSuggestion(AiContext context) {
		Optional<AiProvider> provider = getActiveProvider();
		if (provider.isEmpty()) {
			log.debug("No active AI provider; returning unavailable result for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}
		try {
			return provider.get().generateSuggestion(context);
		} catch (Exception ex) {
			log.warn("AI provider threw exception for type={}: {}", context.suggestionType(), ex.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// Visible for testing
	boolean isAiEnabledFlag() {
		return aiEnabled;
	}

	void setAiEnabled(boolean aiEnabled) {
		this.aiEnabled = aiEnabled;
	}
}

package com.weeklycommit.ai.provider;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion,
		/**
		 * Prompt template version identifier for A/B testing (e.g.
		 * "commit-draft-assist-v1"). May be null for older results.
		 */
		String promptVersion) {

	/**
	 * Backwards-compatible constructor for callers that do not yet provide a prompt
	 * version.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion) {
		this(available, payload, rationale, confidence, modelVersion, null);
	}

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none", null);
	}
}

package com.weeklycommit.ai.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Provides commit drafting assistance (PRD §17 capability 1).
 *
 * <p>
 * Suggestions are editable proposals — they are never auto-applied.
 */
@Service
@Transactional
public class CommitDraftAssistService {

	private static final Logger log = LoggerFactory.getLogger(CommitDraftAssistService.class);

	private final AiProviderRegistry registry;
	private final AiSuggestionService suggestionService;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ObjectMapper objectMapper;

	public CommitDraftAssistService(AiProviderRegistry registry, AiSuggestionService suggestionService,
			WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo, ObjectMapper objectMapper) {
		this.registry = registry;
		this.suggestionService = suggestionService;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.objectMapper = objectMapper;
	}

	/**
	 * Generates commit drafting suggestions for a commit being authored.
	 *
	 * @param request
	 *            the drafting assist request
	 * @return suggestions, or a response with {@code aiAvailable=false} if AI is
	 *         unavailable
	 */
	public CommitDraftAssistResponse assist(CommitDraftAssistRequest request) {
		if (!registry.isAiEnabled()) {
			return CommitDraftAssistResponse.unavailable();
		}

		WeeklyPlan plan = planRepo.findById(request.planId())
				.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + request.planId()));

		List<WeeklyCommit> pastCommits = commitRepo.findByOwnerUserId(plan.getOwnerUserId());

		Map<String, Object> commitData = new HashMap<>();
		commitData.put("title", request.currentTitle());
		commitData.put("description", request.currentDescription());
		commitData.put("successCriteria", request.currentSuccessCriteria());
		commitData.put("estimatePoints", request.currentEstimatePoints());
		commitData.put("chessPiece", request.chessPiece() != null ? request.chessPiece().name() : null);

		Map<String, Object> planData = new HashMap<>();
		planData.put("weekStartDate", plan.getWeekStartDate().toString());
		planData.put("capacityPoints", plan.getCapacityBudgetPoints());

		List<Map<String, Object>> historical = new ArrayList<>();
		for (WeeklyCommit c : pastCommits) {
			Map<String, Object> entry = new HashMap<>();
			entry.put("title", c.getTitle());
			entry.put("estimatePoints", c.getEstimatePoints());
			entry.put("chessPiece", c.getChessPiece() != null ? c.getChessPiece().name() : null);
			historical.add(entry);
		}

		String contextJson = toJson(Map.of("commit", commitData, "plan", planData));

		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, request.userId(), request.planId(),
				request.commitId(), commitData, planData, historical, List.of(), Map.of());

		AiSuggestionResult result = registry.generateSuggestion(context);
		if (!result.available()) {
			return CommitDraftAssistResponse.unavailable();
		}

		AiSuggestion stored = suggestionService.storeSuggestion(AiContext.TYPE_COMMIT_DRAFT, request.userId(),
				request.planId(), request.commitId(), contextJson, result);

		return parseResponse(stored.getId(), result);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private CommitDraftAssistResponse parseResponse(UUID suggestionId, AiSuggestionResult result) {
		try {
			JsonNode node = objectMapper.readTree(result.payload());
			return new CommitDraftAssistResponse(true, suggestionId, textOrNull(node, "suggestedTitle"),
					textOrNull(node, "suggestedDescription"), textOrNull(node, "suggestedSuccessCriteria"),
					node.has("suggestedEstimatePoints") && !node.get("suggestedEstimatePoints").isNull()
							? node.get("suggestedEstimatePoints").asInt()
							: null,
					parseChessPiece(node, "suggestedChessPiece"), result.rationale());
		} catch (JsonProcessingException e) {
			log.warn("Failed to parse AI draft assist payload: {}", e.getMessage());
			return CommitDraftAssistResponse.unavailable();
		}
	}

	private static ChessPiece parseChessPiece(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		try {
			return ChessPiece.valueOf(child.asText().trim().toUpperCase());
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

	private static String textOrNull(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		return child.asText();
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			return "{}";
		}
	}
}

